206: // setPodHostAndAnnotations sets the given pod's host to 'machine' if and only if
207: // the pod is unassigned and merges the provided annotations with those of the pod.
208: // Returns the current state of the pod, or an error.
209: func (r *BindingREST) setPodHostAndAnnotations(ctx context.Context, podUID types.UID, podResourceVersion, podID, machine string, annotations map[string]string, dryRun bool) (finalPod *api.Pod, err error) {
210: 	podKey, err := r.store.KeyFunc(ctx, podID)
211: 	if err != nil {
212: 		return nil, err
213: 	}
214: 
215: 	var preconditions *storage.Preconditions
216: 	if podUID != "" || podResourceVersion != "" {
217: 		preconditions = &storage.Preconditions{}
218: 		if podUID != "" {
219: 			preconditions.UID = &podUID
220: 		}
221: 		if podResourceVersion != "" {
222: 			preconditions.ResourceVersion = &podResourceVersion
223: 		}
224: 	}
225: 
226: 	err = r.store.Storage.GuaranteedUpdate(ctx, podKey, &api.Pod{}, false, preconditions, storage.SimpleUpdate(func(obj runtime.Object) (runtime.Object, error) {
227: 		pod, ok := obj.(*api.Pod)
228: 		if !ok {
229: 			return nil, fmt.Errorf("unexpected object: %#v", obj)
230: 		}
231: 		if pod.DeletionTimestamp != nil {
232: 			return nil, fmt.Errorf("pod %s is being deleted, cannot be assigned to a host", pod.Name)
233: 		}
234: 		if pod.Spec.NodeName != "" {
235: 			return nil, fmt.Errorf("pod %v is already assigned to node %q", pod.Name, pod.Spec.NodeName)
236: 		}
237: 		// Reject binding to a scheduling un-ready Pod.
238: 		if len(pod.Spec.SchedulingGates) != 0 {
239: 			return nil, fmt.Errorf("pod %v has non-empty .spec.schedulingGates", pod.Name)
240: 		}
241: 		pod.Spec.NodeName = machine
242: 		if pod.Annotations == nil {
243: 			pod.Annotations = make(map[string]string)
244: 		}
245: 		for k, v := range annotations {
246: 			pod.Annotations[k] = v
247: 		}
248: 		podutil.UpdatePodCondition(&pod.Status, &api.PodCondition{
249: 			Type:   api.PodScheduled,
250: 			Status: api.ConditionTrue,
251: 		})
252: 		finalPod = pod
253: 		return pod, nil
254: 	}), dryRun, nil)
255: 	return finalPod, err
256: }
