258: // assignPod assigns the given pod to the given machine.
259: func (r *BindingREST) assignPod(ctx context.Context, podUID types.UID, podResourceVersion, podID string, machine string, annotations map[string]string, dryRun bool) (err error) {
260: 	if _, err = r.setPodHostAndAnnotations(ctx, podUID, podResourceVersion, podID, machine, annotations, dryRun); err != nil {
261: 		err = storeerr.InterpretGetError(err, api.Resource("pods"), podID)
262: 		err = storeerr.InterpretUpdateError(err, api.Resource("pods"), podID)
263: 		if _, ok := err.(*errors.StatusError); !ok {
264: 			err = errors.NewConflict(api.Resource("pods/binding"), podID, err)
265: 		}
266: 	}
267: 	return
268: }
