26: // New creates Client from config.
27: // Caller is responsible to call Close() to clean up client.
28: func New(cfg clientv3.Config) (*Client, error) {
29: 	c, err := clientv3.New(cfg)
30: 	if err != nil {
31: 		return nil, err
32: 	}
33: 	kc := &Client{
34: 		Client: c,
35: 	}
36: 	kc.Kubernetes = kc
37: 	return kc, nil
38: }
39: 
40: type Client struct {
41: 	*clientv3.Client
42: 	Kubernetes Interface
43: }
44: 
45: var _ Interface = (*Client)(nil)
46: 
47: func (k Client) Get(ctx context.Context, key string, opts GetOptions) (resp GetResponse, err error) {
48: 	rangeResp, err := k.KV.Get(ctx, key, clientv3.WithRev(opts.Revision), clientv3.WithLimit(1))
49: 	if err != nil {
50: 		return resp, err
51: 	}
52: 	resp.Revision = rangeResp.Header.Revision
53: 	if len(rangeResp.Kvs) == 1 {
54: 		resp.KV = rangeResp.Kvs[0]
55: 	}
56: 	return resp, nil
57: }
58: 
59: func (k Client) List(ctx context.Context, prefix string, opts ListOptions) (resp ListResponse, err error) {
60: 	rangeStart := prefix
61: 	if opts.Continue != "" {
62: 		rangeStart = opts.Continue
63: 	}
64: 	rangeEnd := clientv3.GetPrefixRangeEnd(prefix)
65: 	rangeResp, err := k.KV.Get(ctx, rangeStart, clientv3.WithRange(rangeEnd), clientv3.WithLimit(opts.Limit), clientv3.WithRev(opts.Revision))
66: 	if err != nil {
67: 		return resp, err
68: 	}
69: 	resp.Kvs = rangeResp.Kvs
70: 	resp.Count = rangeResp.Count
71: 	resp.Revision = rangeResp.Header.Revision
72: 	return resp, nil
73: }
74: 
75: func (k Client) Count(ctx context.Context, prefix string, _ CountOptions) (int64, error) {
76: 	resp, err := k.KV.Get(ctx, prefix, clientv3.WithPrefix(), clientv3.WithCountOnly())
77: 	if err != nil {
78: 		return 0, err
79: 	}
80: 	return resp.Count, nil
81: }
